// // This NOR gate is active-high, meaning Y is HIGH when any of A, B, or C_N is HIGH.
module top_module(
    Y   ,
    A   ,
    B   ,
    C_N ,
    VPWR,
    VGND,
    VPB ,
    VNB
);output Y   ;
    input  A   ;
    input  B   ;
    input  C_N ;
    input  VPWR;
    input  VGND;
    input  VPB ;
    input  VNB ;

    assign Y = ~(A | B | C_N);

endmodule
